var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"하아, 하아, 하아……!","JPN":"はぁ、はぁ、はぁ……！","ENG":"*Huff* *Huff* *Huff…!*","TWN":"哈啊，哈啊，哈啊……！"},"stage":{"bg":"THEATER","slots":{"L":null,"C":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"말도 안 돼…….","JPN":"そんな……","ENG":"No... this can't be happening...","TWN":"這不可能……"},"stage":{"bg":"THEATER","slots":{"L":null,"C":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"이런 건… 이런 건 전부 다 거짓말이에요……!","JPN":"こんなの……こんなの全部嘘です……！","ENG":"This is all... this is all a lie...!","TWN":"這種事……這種事全都是騙人的……！"},"stage":{"bg":"THEATER","slots":{"L":null,"C":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"겨우 며칠… 제가 사라졌다고, 다들 저에 대해서 잊어버린다고요?","JPN":"たった数日……私がいなくなったからって、みんな私のことを忘れる？","ENG":"A few days... I disappear for just a few days, and everyone forgets me?","TWN":"才幾天……就因為我消失了，大家就會忘記我嗎？"},"stage":{"bg":"THEATER","slots":{"L":null,"C":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"대답해요, 스완! 이건 말이 안 되잖아요!","JPN":"答えてください、スワン！　こんなのはおかしいじゃないですか！","ENG":"Answer me, Swan! None of this makes sense!","TWN":"回答我，史旺！這簡直不可理喻！"},"stage":{"bg":"THEATER","slots":{"L":null,"C":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"저는 안 속아요! 어차피 모든 건, 당신이 절 속이기 위해 만들어낸 거짓말일 테니까!","JPN":"私は騙されません！　どうせ全部あなたが私を騙すために作り上げた嘘でしょうから！","ENG":"I'm not falling for it! You made all of this up to deceive me, didn't you?!","TWN":"我不會上當的！反正一切都是你為了騙我而編造的謊言！"},"stage":{"bg":"THEATER","slots":{"L":null,"C":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"글쎄요? 이미 말씀드렸을 텐데요.","JPN":"さあ？　言ったはずです。","ENG":"Oh? I believe I already told you.","TWN":"是麼？我應該說過了。"},"stage":{"bg":"THEATER","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"이 극장은 클리파 허수 에너지를 통해, 제 기억이 무한히 반복되는 공간.","JPN":"この劇場はクリファ虚数エネルギーによって私の記憶が無限に繰り返される空間。","ENG":"This theater is a space where my memories endlessly repeat, through Qlipha Imaginary Energy.","TWN":"這個劇場是透過逆卡巴拉虛數能量，使我的記憶無限重複的空間。"},"stage":{"bg":"THEATER","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"이곳에서 상영되는 각본의 소재는 특정 시점의 <color=#ffd34c>과거</color>입니다.","JPN":"ここで上映される脚本の素材は、特定時点の<color=#ffd34c>過去</color>です。","ENG":"The script performed in this theater is drawn from a specific point in the <color=#ffd34c>past</color>.","TWN":"這裡上映的劇本題材是特定時間點的<color=#ffd34c>過去</color>。"},"stage":{"bg":"THEATER","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"정확히는, 제가 직접 혹은 간접적으로 얻은 모든 정보를 각본으로써 재구성한 거죠.","JPN":"厳密には、私が直接的または間接的に取得したすべての情報を、脚本として再構成したものですね。","ENG":"More precisely, they're reconstructions of information I've gathered, either directly or indirectly.","TWN":"準確來說，我是將自己直接或間接獲得的所有資訊重新編寫成劇本的。"},"stage":{"bg":"THEATER","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS2"}}}},{"id":"L17_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"즉, 당신이 부정하든, 부정하지 않든… 정보 말소는 틀림없이 현실에서 발생한 사건이에요.","JPN":"つまり、あなたが否定してもしなくても……情報抹消は間違いなく、現実で発生した事件なのです。","ENG":"So whether you choose to accept it or not... information erasure is something that really did happen.","TWN":"也就是說，無論你是否否認……資訊抹消確實是在現實中發生的事件。"},"stage":{"bg":"THEATER","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS2"}}}},{"id":"L18_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"정보 말소라고요……?","JPN":"情報抹消……？","ENG":"Information erasure...?","TWN":"資訊抹消嗎……？"},"stage":{"bg":"THEATER","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS"}}}},{"id":"L20_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"정보 말소는 클리파 허수 에너지에 의해, 존재 자체에 간섭이 일어나는 현상.","JPN":"情報抹消はクリファ虚数エネルギーによって存在そのものに干渉が発生する現象。","ENG":"Information erasure is a phenomenon where Qlipha Imaginary Energy interferes with a being's very existence.","TWN":"資訊抹消是因逆卡巴拉虛空能量導致存在本身被干涉的現象。"},"stage":{"bg":"THEATER","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"다시 말해, 강력한 정보 오염의 일종이라고 할 수 있죠.","JPN":"まあ、強力な情報汚染の一種とも言えるでしょう。","ENG":"In other words, it's a form of extreme data corruption.","TWN":"換句話說，可以說是一種強力的資訊污染。"},"stage":{"bg":"THEATER","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"물론, 정보 말소를 일으키는 원인은 여러 가지지만…….","JPN":"もちろん、情報抹消を発生させる原因はいろいろありますが……","ENG":"Of course, there are many potential causes behind information erasure...","TWN":"當然，引起資訊抹消現象的原因有很多種……"},"stage":{"bg":"THEATER","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"애초부터 당신은 세계를 만드는 법칙의 이변으로, 현실에 편입된 불안정한 존재입니다.","JPN":"そもそもあなたは世界を作る法則の異変で現実に編入された、不安定な存在。","ENG":"From the beginning, you've been an unstable existence, an anomaly inserted into reality due to a disturbance in the law of creating a world.","TWN":"從一開始，你就是世界法則的異變，是融入現實的不穩定存在。"},"stage":{"bg":"THEATER","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"거울 속의 클리파 차원에 잠시 가두어 두는 것만으로도 정보 말소를 유발할 수 있죠.","JPN":"ですから、鏡の中のクリファ次元にしばらく閉じ込めておくだけで、情報抹消を誘導することができるのです。","ENG":"Even briefly confining you in the Qlipha Dimension in a mirror is enough to trigger information erasure.","TWN":"只需將其暫時困在鏡中逆卡巴拉次元中，就能引發資訊抹消。"},"stage":{"bg":"THEATER","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"무, 무슨 말인지 모르겠어요!","JPN":"な、何のことだかわかりません！","ENG":"I-I don't understand what you're saying!","TWN":"嗯？我、我聽不懂你在說什麼！"},"stage":{"bg":"THEATER","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS2"}}}},{"id":"L28_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"정보 말소를 유발한다고요? 대체 그게 무슨……?","JPN":"情報抹消を誘導する？　いったいどういう……？","ENG":"Trigger information erasure? What does that even mean...?","TWN":"會導致資訊抹消？那到底是……？"},"stage":{"bg":"THEATER","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS"}}}},{"id":"L29_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그건 간단한 이야기랍니다, 노엘.","JPN":"簡単な話ですよ、ノエル。","ENG":"It's quite simple, Noelle.","TWN":"那是個簡單的故事，洛艾兒。"},"stage":{"bg":"THEATER","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS"}}}},{"id":"L30_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"원래 세계의 입장에서 당신이라는 존재는 결국 이물질에 불과하다는 뜻이에요.","JPN":"元の世界にとって、あなたという存在は異物にすぎないということです。","ENG":"From the perspective of the original world, your existence is nothing more than a foreign object.","TWN":"從原本世界的角度來看，你這個存在終究不過是異物罷了。"},"stage":{"bg":"THEATER","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS"}}}},{"id":"L31_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"이물질이라고요……?","JPN":"異物……？","ENG":"A foreign object...?","TWN":"異物……？"},"stage":{"bg":"THEATER","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SURPRISE"}}}},{"id":"L33_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그래요. 원래라면 존재할 리 없는 이물질.","JPN":"そう。本来なら存在するはずのない異物。","ENG":"That's right. A foreign object that was never meant to exist in the first place.","TWN":"是啊，原本不應該存在的異物。"},"stage":{"bg":"THEATER","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"따라서 당신이 사라진 것으로 세계는 처음부터 당신이 없었던 것으로 역사를 수복한 거죠.","JPN":"だからあなたが消えたことで、世界は最初からあなたなど存在しなかったと、歴史を修復したのです。","ENG":"And so, when you disappeared, the world corrected itself by rewriting history as if you were never there.","TWN":"因此，隨著你的消失，世界從一開始就修復了沒有你的歷史。"},"stage":{"bg":"THEATER","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"이것이야말로… 당신이 마주한 현실이자, 당신이라는 존재의 소실…….","JPN":"これこそが、あなたが向き合った現実であり、あなたという存在の消失……","ENG":"This is the reality you now face... the disappearance of who you are.","TWN":"這就是……你所面對的現實，也是你這個存在的消失……"},"stage":{"bg":"THEATER","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그리고 제 두 번째 각본이에요.","JPN":"そして私の、2本目の脚本です。","ENG":"And this... is my second script.","TWN":"這是我的第二個劇本。"},"stage":{"bg":"THEATER","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"THEATER","slots":{"L":null,"C":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS2"},"R":null}}}]`);export{e as default};